package main

import (
	"encoding/gob"
	"fmt"
	"os"
)

// UserSession represents a user session
type UserSession struct {
	ID       int
	Prefs    map[string]interface{}
	Perms    []string
}

func main() {
	// Create a new user session
	session := &UserSession{
		ID:       123,
		Prefs:    map[string]interface{}{"theme": "dark"},
		Perms:    []string{"admin", "user"},
	}

	// Serialize the user session to disk using gob encoding
	f, err := os.Create("session.gob")
	if err != nil {
		fmt.Println(err)
		return
	}
	defer f.Close()

	encoder := gob.NewEncoder(f)
	err = encoder.Encode(session)
	if err != nil {
		fmt.Println(err)
		return
	}

	// Reload the user session from disk
	f, err = os.Open("session.gob")
	if err != nil {
		fmt.Println(err)
		return
	}
	defer f.Close()

	decoder := gob.NewDecoder(f)
	var loadedSession UserSession
	err = decoder.Decode(&loadedSession)
	if err != nil {
		fmt.Println(err)
		return
	}

	// Print the user session to the console
	fmt.Println("User ID:", loadedSession.ID)
	fmt.Println("Preferences:")
	for k, v := range loadedSession.Prefs {
		fmt.Printf("\t%s: %v\n", k, v)
	}
	fmt.Println("Permissions:")
	for _, perm := range loadedSession.Perms {
		fmt.Printf("\t%s\n", perm)
	}
}